-- W1.6 questions batch 4813/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-5ff21eeb-moex-00124', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'essay', '甲乙原為夫妻，育有未成年子女丙，嗣後甲、乙感情生變離婚後，共同約
定將丙事實上之保護教養事項，委由甲之母親丁監護。丙於青春期時學
壞，在外參加幫派屢涉非行，丁年紀大深覺無力管教，而欲終止該委託，
惟當時甲已死亡，乙已經再婚不願再管丙的事。試問：甲乙當時與丁所約
定之契約性質為何？丁得否終止與乙之契約關係？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00125', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'essay', '甲與其孫乙簽訂贈與契約書，將其所有不動產贈與乙，並約定甲贈與不動
產於乙，且乙應扶養甲，嗣後乙又將此債權轉讓於丙，甲於尚未辦理所有
權移轉登記前突然死亡，甲之繼承人為丁戊等二人，試問：乙或丙得否請
求甲之繼承人丁戊履行原本甲應負移轉該不動產所有權之義務？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00126', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲乙丙三人為A法人之董事，約定僅甲乙有對外代表權，甲之權限為人事招聘，乙之權限為人事 以外之綜合事務。下列敘述，何者正確？', '["該代表權限制之約定得對抗任何第三人", "丙就法人一切事務，對外代表法人之限制，須以章程為之", "甲乙對外代表為人事招聘或綜合事務之權限區分，須以章程為之", "此等對丙之對外代表權限之限制，若未以章程為之，不得對抗善意第三人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00127', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲為A屋之所有人，下列關於A屋之買賣契約，何者無效？', '["甲乙訂立買賣A屋之契約，卻均不知A屋已經於該買賣契約締結之前夕，因火災而片瓦不留", "甲將A屋出租於乙，其後將A屋出賣於丙", "乙明知A屋為甲所有，卻將A屋出賣於知情之丙", "甲先將A屋出賣於乙，又將A屋出賣於丙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00128', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於民法第107條代理權限制及撤回之敘述，何者錯誤？', '["第三人因過失而不知其事實者，本人不得以代理權之限制及撤回對抗之", "本條亦可能構成表見代理", "相對人如不主張表見代理，則依無權代理之規定處理", "相對人明知無權代理人無代理權，或依情形可得而知，而仍與其為法律行為，則本人不負授權 人之責任 32820、33320 33620"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00129', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '依民法規定，下列關於時效中斷效力之敘述，何者錯誤？', '["時效因請求而中斷者，其意思表示於相對人所了解或到達相對人時，時效期間重行起算", "時效因起訴而中斷者，自受確定判決時，時效期間重行起算", "時效因聲請發支付命令而中斷者，自受支付命令之裁定確定時，時效期間重行起算", "經假執行裁定所確定之請求權，其原有消滅時效期間不滿5年者，因中斷而重行起算之時效期間 為5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00130', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲與其配偶乙報名丙旅行社所主辦之櫻花之旅，但行前乙臨時身體不適，向丙請求改由自己已退 休多年之父丁參加旅遊。丁是高齡者，可以減少旅行途中之交通費以及門票等費用，乙便請求丙 退還減少之部分，丙不許。出發到當地，甲發現櫻花根本還沒有開，憤而要求終止契約，丁則繼 續參加完行程，但全程都沒看到櫻花。下列敘述，何者正確？', '["乙於旅遊開始即變更由丁參加旅遊，因此減少之費用，得請求退還", "甲依民法第514條之7規定，終止契約時，丙應將甲送回原出發地，其所生之費用，由甲負擔", "丁雖然全程參加完行程，但沒看到櫻花時，若可歸責於丙，而不具備旅遊服務之品質，則丁得 向丙請求減少費用", "旅遊完成後，旅客得隨時終止契約，但應賠償旅遊營業人因契約終止而生之損害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00131', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '拍賣乃特種買賣，民法對於拍賣人之規定，下列敘述，何者錯誤？', '["拍賣人對於其所經管之拍賣，不得應買，亦不得使他人為其應買", "拍賣人拍板或依其他慣用之方法為賣定之表示者，拍賣因而成立", "應買人所為之應買之表示，雖有出價較高之應買，仍不失其拘束力", "拍賣人對於應買人所出最高之價，認為不足者，得不為賣定之表示而撤回其物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00132', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於保證契約之敘述，何者錯誤？', '["保證人之先訴抗辯權，得預先拋棄", "主債務人已拋棄之抗辯，保證人不得主張", "主債務人債務履行遲延時，保證人得向其請求除去保證責任", "數人保證同一債務時，原則上應負連帶責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00133', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲、乙、丙以合夥方式經營事業，下列敘述，何者正確？', '["民法所稱合夥，係指3人以上互約出資，以經營共同事業之契約", "甲、乙、丙之出資，屬於其分別共有", "乙欲以勞務為出資，但因民法合夥契約之規定，無法為之", "事業經營中，若有發生損害而導致資本減少，原則上甲、乙、丙並無補充資本之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
